-- 029_puestos_reales.sql
-- 1. Hacer nullable rango_id y fecha_incorporacion en personas (para datos incompletos)
-- 2. Resetear oficinas con IDs coherentes
-- 3. Borrar puestos ficticios del seed e insertar 74 puestos reales

BEGIN;

-- ================================================================
-- PARTE 1: Ajustar columnas nullable en personas
-- ================================================================
ALTER TABLE personas ALTER COLUMN rango_id DROP NOT NULL;
ALTER TABLE personas ALTER COLUMN fecha_incorporacion DROP NOT NULL;

-- ================================================================
-- PARTE 2: Resetear oficinas (IDs del seed se desincronizaron con migraciones)
-- ================================================================
DELETE FROM oficinas;

INSERT INTO oficinas (id, nombre) VALUES
